@startuml
skinparam classDiagram
    class Actor {
        label "I" as icon
    }
    class Database {
        label "C" as icon
    }

    class Printer {
        interface
        label "Printer"
        method "void print(Document)"
    }

    class Scanner {
        interface
        label "Scanner"
        method "void scan(Document)"
    }

    class SimplePrinter {
        database
        label "SimplePrinter"
        method "void print(Document)"
    }

    class SimplePrinterScanner {
        database
        label "SimplePrinterScanner"
        method "void print(Document)"
        method "void scan(Document)"
    }

    Actor --> Printer : inherits
    Actor --> Scanner : inherits
    Actor --> SimplePrinter : inherits
    Actor --> SimplePrinterScanner : inherits

    Printer ..> SimplePrinter : implements
    Printer ..> SimplePrinterScanner : implements
    Scanner ..> SimplePrinterScanner : implements

@enduml
